/**
 * Evaluator types.
 *
 * The evaluator takes TypeScript source text produced by the SDK emitter (or
 * hand-authored by the user / generated by the chat assistant) and returns a
 * structured flow definition — nodes + edges + metadata. Input sources
 * typically look like:
 *
 *   import { defineFlow, input, code, output } from '@invect/sdk';
 *   import { gmailSendMessageAction } from '@invect/actions/gmail';
 *
 *   export default defineFlow({ nodes: [...], edges: [...] });
 *
 * The evaluator enforces a module-import allowlist — `@invect/sdk` (and
 * subpaths), `@invect/action-kit`, and `@invect/actions/*`. Any extra
 * specifiers the caller wants to permit can be added via
 * `additionalAllowedImports`; those modules must resolve via normal Node
 * module resolution from the evaluator's cwd or node_modules tree.
 * Everything else (node builtins, user filesystem paths, network fetches)
 * is blocked via a pre-eval source scan.
 */

import type { ResolvedEdge, SdkFlowNode } from '../types';

export interface EvaluatorOptions {
  /**
   * Additional import specifiers to allow through the pre-eval scan. The
   * module must be resolvable via Node's own resolution (e.g. a workspace
   * or globally-installed action package the caller has already added as a
   * dependency). Defaults to `[]`.
   */
  additionalAllowedImports?: string[];

  /**
   * Max time in milliseconds the evaluation may take before it is aborted.
   * Defaults to 10_000. Does NOT interrupt synchronous infinite loops (that
   * needs a Worker — future enhancement).
   */
  timeoutMs?: number;

  /**
   * Optional import specifier that resolves the `@invect/sdk` itself. Tests
   * pin this to the live workspace path; production callers should leave it
   * unset (defaults to `@invect/sdk`).
   */
  sdkImportSpecifier?: string;
}

export interface EvaluatedFlow {
  /** The flow's exported nodes after `defineFlow` ran. */
  nodes: SdkFlowNode[];
  /** Edges normalised by `defineFlow` (tuple → object form). */
  edges: ResolvedEdge[];
  /** Flow metadata (name/description/tags), if set by the source. */
  metadata?: { name?: string; description?: string; tags?: string[] };
}

export type EvaluatorErrorCode =
  | 'import-forbidden'
  | 'import-parse-failed'
  | 'dynamic-import'
  | 'eval-failed'
  | 'no-default-export'
  | 'default-export-not-a-flow'
  | 'timeout';

export interface EvaluatorError {
  code: EvaluatorErrorCode;
  message: string;
  /** The offending import specifier, when applicable. */
  specifier?: string;
  /** Optional line number within the source text. */
  line?: number;
}

export interface EvaluatorResult {
  /** The evaluated flow, if evaluation succeeded. */
  flow: EvaluatedFlow | null;
  /** Any errors that prevented a successful evaluation. */
  errors: EvaluatorError[];
  /** True when `flow` is non-null. */
  ok: boolean;
}
